module RefModule(
  input clk,
  input reset,
  input enable,
  input d,
  output reg q
);reg q_next;
  wire _tap_clk = clk & {1{1'b1}};


  always @(posedge clk) begin
    if (reset) begin
      q_next <= 1'b0;
    end else if (enable) begin
      q_next <= d;
    end else begin
      q_next <= q;
    end
  end

  assign q = q_next;

endmodule
